sql:
SELECT headline, category
FROM news
ORDER BY datetime DESC;

SELECT open, close, volume, bid
FROM market_data
WHERE asset_id = 1 AND datetime = '2023-05-01';

SELECT asset_name
FROM assets
WHERE asset_id = (SELECT MAX(asset_id) FROM assets);

SELECT SUM(volume) AS total_volume
FROM market_data
WHERE asset_id = 0 AND datetime = '2023-01-01';

SELECT datetime, close
FROM market_data
WHERE asset_id = 1 AND datetime >= '2023-05-01' AND datetime < '2023-06-01';
